#!/usr/bin/env bash
# Generated by @navori/plugin-semgrep. Runs semgrep over TS/TSX files changed
# vs `{{branchBase}}` with the `auto` ruleset. Skips silently if semgrep or
# git are absent — the tool is optional.
#
# Triggered as a PreToolUse(Bash) hook, gated inline to fire only on
# `git commit` / `git push`.

set -euo pipefail

cmd=$(jq -r '.tool_input.command // empty' 2>/dev/null || true)
case "$cmd" in
  'git commit'*|'git push'*) ;;
  *) exit 0 ;;
esac

if ! command -v semgrep >/dev/null 2>&1; then
  echo "⊘ semgrep no instalado localmente — skip (install: brew install semgrep)" >&2
  exit 0
fi

if ! git rev-parse --git-dir >/dev/null 2>&1; then
  exit 0
fi

if ! git rev-parse --verify {{branchBase}} >/dev/null 2>&1; then
  echo "⊘ branch '{{branchBase}}' no existe localmente — skip semgrep" >&2
  exit 0
fi

files=$(git diff --name-only --diff-filter=ACMRT {{branchBase}} 2>/dev/null | grep -E '\.tsx?$' || true)
if [ -z "$files" ]; then
  echo "✓ semgrep: sin cambios vs {{branchBase}}" >&2
  exit 0
fi

count=$(echo "$files" | wc -l | tr -d ' ')
echo "▶ semgrep: $count archivo(s) modificados vs {{branchBase}}" >&2

echo "$files" | xargs semgrep scan \
  --config=auto \
  --error \
  --metrics=off
